4,-0.030870238319039345,-0.034159597009420395,0.024901477620005608,0.023128623142838478,0.022815387696027756,-0.040410373359918594,-0.031028104946017265,-0.015683738514780998,0.04496607556939125,-0.023247020319104195,-0.03158096969127655]';
