  PERFORM __mj."spUpdateComponent"(p_Namespace := p_Namespace_027f8063, p_Name := p_Name_027f8063, p_Version := p_Version_027f8063, p_VersionSequence := p_VersionSequence_027f8063, p_Title := p_Title_027f8063, p_Description := p_Description_027f8063, p_Type := p_Type_027f8063, p_Status := p_Status_027f8063, p_DeveloperName := p_DeveloperName_027f8063, p_DeveloperName_Clear := TRUE, p_DeveloperEmail := p_DeveloperEmail_027f8063, p_DeveloperEmail_Clear := TRUE, p_DeveloperOrganization := p_DeveloperOrganization_027f8063, p_DeveloperOrganization_Clear := TRUE, p_SourceRegistryID := p_SourceRegistryID_027f8063, p_SourceRegistryID_Clear := TRUE, p_ReplicatedAt := p_ReplicatedAt_027f8063, p_ReplicatedAt_Clear := TRUE, p_LastSyncedAt := p_LastSyncedAt_027f8063, p_LastSyncedAt_Clear := TRUE, p_Specification := p_Specification_027f8063, p_FunctionalRequirements := p_FunctionalRequirements_027f8063, p_TechnicalDesign := p_TechnicalDesign_027f8063, p_FunctionalRequirementsVector := p_FunctionalRequirementsVector_027f8063, p_TechnicalDesignVector := p_TechnicalDesignVector_027f8063, p_HasCustomProps := p_HasCustomProps_027f8063, p_HasCustomEvents := p_HasCustomEvents_027f8063, p_RequiresData := p_RequiresData_027f8063, p_DependencyCount := p_DependencyCount_027f8063, p_TechnicalDesignVectorEmbeddingModelID := p_TechnicalDesignVectorEmbeddingModelID_027f8063, p_FunctionalRequirementsVectorEmbeddingModelID := p_FunctionalRequirementsVectorEmbeddingModelID_027f8063, p_HasRequiredCustomProps := p_HasRequiredCustomProps_027f8063, p_ID := p_ID_027f8063);
END $mj$;

-- Save MJ: Components (core SP call only)
DO $mj$
