  PERFORM __mj."spUpdateComponent"(p_Namespace := p_Namespace_f00c9726, p_Name := p_Name_f00c9726, p_Version := p_Version_f00c9726, p_VersionSequence := p_VersionSequence_f00c9726, p_Title := p_Title_f00c9726, p_Description := p_Description_f00c9726, p_Type := p_Type_f00c9726, p_Status := p_Status_f00c9726, p_DeveloperName := p_DeveloperName_f00c9726, p_DeveloperName_Clear := TRUE, p_DeveloperEmail := p_DeveloperEmail_f00c9726, p_DeveloperEmail_Clear := TRUE, p_DeveloperOrganization := p_DeveloperOrganization_f00c9726, p_DeveloperOrganization_Clear := TRUE, p_SourceRegistryID := p_SourceRegistryID_f00c9726, p_SourceRegistryID_Clear := TRUE, p_ReplicatedAt := p_ReplicatedAt_f00c9726, p_ReplicatedAt_Clear := TRUE, p_LastSyncedAt := p_LastSyncedAt_f00c9726, p_LastSyncedAt_Clear := TRUE, p_Specification := p_Specification_f00c9726, p_FunctionalRequirements := p_FunctionalRequirements_f00c9726, p_TechnicalDesign := p_TechnicalDesign_f00c9726, p_FunctionalRequirementsVector := p_FunctionalRequirementsVector_f00c9726, p_TechnicalDesignVector := p_TechnicalDesignVector_f00c9726, p_HasCustomProps := p_HasCustomProps_f00c9726, p_HasCustomEvents := p_HasCustomEvents_f00c9726, p_RequiresData := p_RequiresData_f00c9726, p_DependencyCount := p_DependencyCount_f00c9726, p_TechnicalDesignVectorEmbeddingModelID := p_TechnicalDesignVectorEmbeddingModelID_f00c9726, p_FunctionalRequirementsVectorEmbeddingModelID := p_FunctionalRequirementsVectorEmbeddingModelID_f00c9726, p_HasRequiredCustomProps := p_HasRequiredCustomProps_f00c9726, p_ID := p_ID_f00c9726);
